import os
from web3 import Web3

print("\n--- 🚀 Initializing Blockchain Gatekeeper 🚀 ---")

# 1. Connect to Ganache (override via: export BLOCKCHAIN_URL="http://<MAC_IP>:7545")
w3 = Web3(Web3.HTTPProvider(os.environ.get("BLOCKCHAIN_URL", "http://127.0.0.1:7545")))

if not w3.is_connected():
    print("❌ Error: Could not connect to Ganache. Is the app open and running on port 7545?")
    exit()

print("✅ Connected to Ganache successfully!")

# 2. Set the owner account (using the very first account Ganache gives us)
my_account = w3.eth.accounts[0]
w3.eth.default_account = my_account
print(f"[*] Using Admin Wallet: {my_account}")

# 3. Contract Data
contract_abi = [{"inputs": [{"internalType": "address","name": "_deviceAddr","type": "address"},{"internalType": "string","name": "_name","type": "string"},{"internalType": "uint256","name": "_fingerprint","type": "uint256"}],"name": "registerDevice","outputs": [],"stateMutability": "nonpayable","type": "function"},{"inputs": [],"stateMutability": "nonpayable","type": "constructor"},{"inputs": [{"internalType": "address","name": "","type": "address"}],"name": "devices","outputs": [{"internalType": "string","name": "name","type": "string"},{"internalType": "bool","name": "isAuthorized","type": "bool"},{"internalType": "uint256","name": "lastFingerprint","type": "uint256"}],"stateMutability": "view","type": "function"},{"inputs": [{"internalType": "address","name": "_deviceAddr","type": "address"}],"name": "isAllowed","outputs": [{"internalType": "bool","name": "","type": "bool"}],"stateMutability": "view","type": "function"},{"inputs": [],"name": "owner","outputs": [{"internalType": "address","name": "","type": "address"}],"stateMutability": "view","type": "function"}]

# We add '0x' to the front of your bytecode so Python knows it's hex data
contract_bytecode = ""
# 4. Create Contract Instance
DeviceRegistry = w3.eth.contract(abi=contract_abi, bytecode=contract_bytecode)

# 5. Deploy Contract
print("[*] Deploying Smart Contract...")
tx_hash = DeviceRegistry.constructor().transact({'from': my_account})
tx_receipt = w3.eth.wait_for_transaction_receipt(tx_hash)

contract_address = tx_receipt.contractAddress
print(f"✅ Contract successfully deployed at: {contract_address}")

# 6. Register the Device automatically
print(f"[*] Registering Raspberry Pi to the Blockchain...")
contract = w3.eth.contract(address=contract_address, abi=contract_abi)
register_tx = contract.functions.registerDevice(my_account, "RaspberryPi_Mridul", 100).transact({'from': my_account})
w3.eth.wait_for_transaction_receipt(register_tx)

print(f"✅ Device registered successfully!")
print("\n=== DEPLOYMENT COMPLETE ===")
print("IMPORTANT: Copy the Contract Address and Admin Wallet above.")
print("Paste them into your final_system.py script to make it live!")
